# Module defining base shape abstractions

interface IMeasurable:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...

interface IRender:
    def render(self) -> str: ...

@abstract
class Shape:
    name: str
    id: int

    def __init__(self, name: str, id: int):
        self.name = name
        self.id = id

    @abstract
    def describe(self) -> str: ...

    @virtual
    def info(self) -> str:
        return f"Shape {{self.name}} (ID: {{self.id}})"

