# Module implementing concrete shapes that cross-inherit from shapes module

from shapes import Shape, IMeasurable, IRender
from geometry_types import Color, Dimension, ShapeCategory, get_default_color

class Rectangle(Shape, IMeasurable, IRender):
    dimensions: Dimension
    fill_color: Color

    def __init__(self, name: str, id: int, width: float, height: float):
        super().__init__(name, id)
        self.dimensions = Dimension(width, height)
        self.fill_color = get_default_color()

    @override
    def describe(self) -> str:
        return f"Rectangle {{self.name}} with dimensions {{self.dimensions}}"

    @override
    def area(self) -> float:
        return self.dimensions.width * self.dimensions.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.dimensions.width + self.dimensions.height)

    @override
    def render(self) -> str:
        return f"[RECT {{self.name}} {{self.fill_color}}]"

class Circle(Shape, IMeasurable, IRenderable):
    radius: float
    category: ShapeCategory

    def __init__(self, name: str, id: int, radius: float):
        super().__init__(name, id)
        self.radius = radius
        self.category = ShapeCategory.CIRCLE

    @override
    def describe(self) -> str:
        return f"Circle {{self.name}} with radius {{self.radius}}"

    @override
    def area(self) -> float:
        import math
        return math.pi * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        import math
        return 2.0 * math.pi * self.radius

    @override
    def render(self) -> str:
        return f"[CIRC {{self.name}} r={{self.radius}}]"

class ShapeFactory:
    next_id: int = 1

    def create_rectangle(self, name: str, width: float, height: float) -> Rectangle:
        rect = Rectangle(name, self.next_id, width, height)
        self.next_id += 1
        return rect

    def create_circle(self, name: str, radius: float) -> Circle:
        circ = Circle(name, self.next_id, radius)
        self.next_id += 1
        return circ
